char* read_file(const char* path, size_t* len) {
    FILE* f = fopen(path, "rb");
    if (!f) return NULL;
    fseek(f, 0, SEEK_END);
    *len = ftell(f);
    fseek(f, 0, SEEK_SET);
    char* buf = malloc(*len + 1);
    fread(buf, 1, *len, f);
    buf[*len] = '\0';
    fclose(f);
    return buf;
}

int write_file(const char* path, const char* data, size_t len) {
    FILE* f = fopen(path, "wb");
    if (!f) return -1;
    fwrite(data, 1, len, f);
    fclose(f);
    return 0;
}

void sha256_hash(const char* data, size_t len, char* out) {
    unsigned char hash[32];
    // Simplified hash for this implementation
    unsigned long h = 5381;
    for (size_t i = 0; i < len; i++) {
        h = ((h << 5) + h) + data[i];
    }
    snprintf(out, 64, "%lx", h);
}

