void add_cmd(const char* filename) {
    struct stat st;
    if (stat(filename, &st) != 0) {
        fprintf(stderr, "Error: %s not found\n", filename);
        return;
    }
    size_t len;
    char* data = read_file(filename, &len);
    if (!data) {
        fprintf(stderr, "Error reading %s\n", filename);
        return;
    }
    char hash[64];
    sha256_hash(data, len, hash);
    char path[256];
    snprintf(path, sizeof(path), ".minigit/objects/%s", hash);
    write_file(path, data, len);
    free(data);

    // Update index
    FILE* index = fopen(".minigit/index", "r");
    FileEntry files[MAX_FILES];
    int count = 0;
    if (index) {
        while (fscanf(index, "%s %s", files[count].filename, files[count].hash) == 2) {
            count++;
        }
        fclose(index);
    }
    int found = 0;
    for (int i = 0; i < count; i++) {
        if (strcmp(files[i].filename, filename) == 0) {
            strcpy(files[i].hash, hash);
            found = 1;
            break;
        }
    }
    if (!found && count < MAX_FILES) {
        strcpy(files[count].filename, filename);
        strcpy(files[count].hash, hash);
        count++;
    }
    index = fopen(".minigit/index", "w");
    for (int i = 0; i < count; i++) {
        fprintf(index, "%s %s\n", files[i].filename, files[i].hash);
    }
    fclose(index);
}

void write_tree_cmd() {
