    if (!index) {
        fprintf(stderr, "Error: no index file\n");
        return;
    }
    FileEntry files[MAX_FILES];
    int count = 0;
    while (fscanf(index, "%s %s", files[count].filename, files[count].hash) == 2) {
        count++;
    }
    fclose(index);

    char tree_data[MAX_LINE * MAX_FILES];
    int offset = 0;
    for (int i = 0; i < count; i++) {
        offset += sprintf(tree_data + offset, "%s %s\n", files[i].filename, files[i].hash);
