void commit_cmd(const char* msg) {
    char branch[MAX_NAME];
    get_head_branch(branch);
    char parent[MAX_HASH];
    get_branch_commit(branch, parent);

    FILE* index = fopen(".minigit/index", "r");
    if (!index) {
        fprintf(stderr, "Error: no index file\n");
        return;
    }
    FileEntry files[MAX_FILES];
