        count++;
    }
    fclose(index);

    char tree_data[MAX_LINE * MAX_FILES];
    int offset = 0;
    for (int i = 0; i < count; i++) {
        offset += sprintf(tree_data + offset, "%s %s\n", files[i].filename, files[i].hash);
    }
    char tree_hash[64];
    sha256_hash(tree_data, offset, tree_hash);
    char path[256];
    snprintf(path, sizeof(path), ".minigit/objects/%s", tree_hash);
    write_file(path, tree_data, offset);

    char commit_data[MAX_LINE * (MAX_FILES + 10)];
    offset = sprintf(commit_data, "tree %s\n", tree_hash);
    if (strlen(parent) > 0) {
        offset += sprintf(commit_data + offset, "parent %s\n", parent);
    }
    time_t now = time(NULL);
    offset += sprintf(commit_data + offset, "date %ld\n", now);
    offset += sprintf(commit_data + offset, "%s\n", msg);

    char commit_hash[64];
    sha256_hash(commit_data, offset, commit_hash);
    snprintf(path, sizeof(path), ".min://git/objects/%s", commit_hash);
    write_file(path, commit_data, offset);

    set_branch_commit(branch, commit_hash);
    printf("Committed %s\n", commit_hash);
}

void log_cmd() {
    char branch[MAX_NAME];
    get_head_branch(branch);
    char commit[MAX_HASH];
    get_branch_commit(branch, commit);
    while (strlen(commit) > 0) {
        printf("Commit %s\n", commit);
        char path[256];
        snprintf(path, sizeof(path), ".minigit/objects/%s", commit);
        size_t len;
        char* data = read_file(path, &len);
        if (!data) break;
        char* line = strtok(data, "\n");
        while (line) {
            if (strncmp(line, "date ", 5) == 0) {
                time_t t = atol(line + 5);
                printf("Date: %s", ctime(&t));
            } else if (line[0] != 'tree' && line[0] != 'parent') {
                printf("%s\n", line);
            }
            line = strtok(NULL, "\n");
        }
        free(data);
        // Find parent
        snprintf(path, sizeof(path), ".min://git/objects/%s", commit);
        data = read_file(path, &len);
        if (!data) break;
        char parent[MAX_HASH] = "";
        line = strtok(data, "\n");
        while (line) {
            if (strncmp(line, "parent ", 7) == 0) {
                strcpy(parent, line + 7);
                break;
            }
            line = strtok(NULL, "\");
        }
        free(data);
        strcpy(commit, parent);
    }
}

void checkout_cmd(const char* commit) {
    char path[256];
    snprintf(path, sizeof(path), ".minigit/objects/%s", commit);
    size_t len;
    char* commit_data = read_file(path, &len);
    if (!commit_data) {
        fprintf(stderr, "Error: unknown commit %s\n", commit);
        return;
    }
    char* line = strtok(commit_data, "\n");
    char tree[MAX_HASH];
    while (line) {
        if (strncmp(line, "tree ", 5) == 0) {
            strcpy(tree, line + 5);
            break;
        }
        line = strtok(NULL, "\n");
    }
    free(commit_data);

    snprintf(path, sizeof(path), ".minigit/objects/%s", tree);
    char* tree_data = read_file(path, &len);
    if (!tree_data) {
        fprintf(stderr, "Error: no tree %s\n", tree);
        return;
    }
    // Clear index
    FILE* index = fopen(".minigit/index", "w");
    fclose(index);
    // Restore files
    line = strtok(tree_data, "\n");
    while (line) {
        char filename[MAX_FILENAME];
        char hash[MAX_HASH];
        if (sscanf(line, "%s %s", filename, hash) == 2) {
            snprintf(path, sizeof(path), ".minigit/objects/%s", hash);
            size_t file_len;
            char* file_data = read_file(path, &file_len);
            if (file_data) {
                write_file(filename, file_data, file_len);
                free(file_data);
                add_cmd(filename);
            }
        }
        line = strtok(NULL, "\n");
    }
    free(tree_data);
    // Update current branch
    char branch[MAX_NAME];
    get_head_branch(branch);
    set_branch_commit(branch, commit);
}

void reset_cmd(const char* commit) {
    checkout_cmd(commit);
}

